import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secretFile.txt";
        String directory = "/var/www/data/";

        // Validate user input to prevent path traversal
        if (!userInput.contains("..") && !userInput.contains("/")) {
            File file = new File(directory + userInput);

            if (file.exists() && file.getAbsolutePath().startsWith(directory)) {
                try {
                    byte[] fileContent = Files.readAllBytes(Paths.get(file.getAbsolutePath()));
                    System.out.println(new String(fileContent));
                } catch (IOException e) {
                    e.printStackTrace();
                }
            } else {
                System.out.println("File not found.");
            }
        } else {
            System.out.println("Invalid input.");
        }
    }
}

